var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>먼 옛날, 사람들의 두려움을 사는 큰 뱀이 있었다.</color>","JPN":"<color=#ffd34c>遥か昔、人々から恐れられた大蛇がいた。</color>","ENG":"<color=#ffd34c>A long time ago, there was a giant snake that everyone feared.</color>","TWN":"<color=#ffd34c>很久很久以前，有條令人害怕的大蛇。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>하지만 바람의 목소리를 들을 줄 아는 여인이 큰 뱀의 외로운 마음을 달래어, 수호신으로 모셨다.</color>","JPN":"<color=#ffd34c>しかし、風の声を聞くことができるとある女が\\n大蛇の寂しさを癒し、守護神として崇めた。</color>","ENG":"<color=#ffd34c>But a woman who could hear the voice of wind soothed the snake, and worshipped it as a guardian god.</color>","TWN":"<color=#ffd34c>但是聽得懂風聲的女人，安慰大蛇孤獨的心情後，將其奉爲守護神。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>뱀은 보답으로 여인을 무녀로 삼고 영생을 선물했다. 피부는 혈색을 잃지 않고 병드는 일이 없었다.</color>","JPN":"<color=#ffd34c>蛇は恩返しとして、女を巫女にして永遠の命を与えた。\\n肌は血色を失わず、病気にかかることもなかった。</color>","ENG":"<color=#ffd34c>The snake made the woman its priestess, and gave her eternal life. The priestess never withered nor sickened.</color>","TWN":"<color=#ffd34c>大蛇將女人視為巫女，並將永生送給她當作回報。巫女的膚色永遠那樣紅潤，也從不生病。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>무녀를 부러워하던 사람들은 문득 생각했다.</color>","JPN":"<color=#ffd34c>巫女を羨ましがっていた人々はふと思った。</color>","ENG":"<color=#ffd34c>Those who were jealous of the priestess came up with an idea:</color>","TWN":"<color=#ffd34c>羨慕巫女的人們突然想到。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>뱀의 힘이 깃든 무녀의 피를 마시면, 우리도 영생을 누릴 수 있지 않을까?</color>","JPN":"<color=#ffd34c>蛇の力が宿った巫女の血を飲めば、\\n私たちも永遠の命を手にすることができるのでは？</color>","ENG":"<color=#ffd34c>If we drink the blood of the priestess, we might live forever, too.</color>","TWN":"<color=#ffd34c>若是巫女的血液中有大蛇的法力，那喝下巫女的血後，我們豈不是也能得到永生嗎？</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"회동은 원래 당주들이 전부 모여야 하는 거 아닌가? 생각보다 너무 적은데?","JPN":"会合は本来なら当主が全員集まらなければならないんだろ？\\n思っていたより人数が少なすぎるようだが。","ENG":"I thought all family leaders were supposed to be here. How come there are so few?","TWN":"不是所有堂主都要參加聚會嗎？人怎麼這麼少？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"다른 당주 분들은 각자 병력을 동원해 봉인역을 지키고 있습니다.","JPN":"他の当主の皆様は各家の兵力を動員して封印域を守っています。","ENG":"Other family leaders are with their own troops, protecting each Seal Domain.","TWN":"其他堂主正在各自動員兵力守護封印域。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"독기에 잠식된 침식체들이 오로치의 봉인을 파괴하려 들고 있으니 말이지요.","JPN":"毒に侵された侵食体たちが、オロチの封印を破壊しようとしているからです。","ENG":"Even now, poisoned C.O.s are attacking the Seal Domains to free Orochi.","TWN":"因為有消息說，被毒氣侵蝕的侵蝕體正試圖破壞大蛇的封印。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저기, 질문 하나 해도 괜찮을까요?","JPN":"あの、一つ質問してもいいですか？","ENG":"Do you mind if I ask you a question?","TWN":"請問我可以問一個問題嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오로치가 정확히 뭐죠? 신화에 등장하는 괴물인가요?","JPN":"オロチとは何ですか？　神話に登場する化け物ですか？","ENG":"What is Orochi? Isn’t that the monster from a myth?","TWN":"大蛇是什麼？是神話中的怪物嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치라면…….","JPN":"オロチは……","ENG":"Orochi is...","TWN":"大蛇是……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"흥. 연합에 얼씬거리지도 않던 방계 집안 자식답게 아무것도 모르는군.","JPN":"ふん。連合に顔すら出さなかった傍系の息子らしく、何も知らないようだな。","ENG":"Hah, you know nothing. But what can we expect from the collateral family that has been ignoring the Alliance for years?","TWN":"哼，果然是都沒在跟聯盟來往的旁系，什麼都不知道！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"사요 님, 저 애송이 말 들으셨지요. 나유카 가문은 진즉 맥이 끊긴 겁니다.","JPN":"小夜様、あの小僧の言葉を聞かれましたね。\\n奈由香家はもう家系が絶たれたと考えてよいでしょう。","ENG":"Elder Sayo, you heard the boy. The Nayuka family is already lost to us.","TWN":"小夜，你有聽到那個小鬼說的話吧？南裕夏家族早就後繼無人啦！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"외부인이나 다름없는데 뭘 기대하겠습니까. 어서 내보내시죠.","JPN":"部外者同然な者に何も期待できませぬ。\\n早くここから出ていってもらいましょう。","ENG":"They are just outsiders. Send this boy away.","TWN":"根本和外人沒什麼兩樣，還要期待什麼？快讓他離開吧！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐라고?! 이 영감이 진짜!","JPN":"はあ！？　何言ってんだジジイ！","ENG":"What did you just say?","TWN":"你說什麼？！臭老頭！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"언성을 낮추세요. 마사키.","JPN":"大声は控えてください、雅紀様。","ENG":"Watch your tone, Masaki.","TWN":"請降低音量，雅紀。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"신화 속의 오로치와 같은 존재라고 볼 수 있겠지만, 가문 연합에서 전해져 내려오는 내력은 알려진 것과 다릅니다.","JPN":"神話のオロチのような存在とみることもできるでしょうが、\\n連合の伝承は知られているものとは異なります。","ENG":"This may be the Orochi from the myth, but the truth we know about this creature is different from the lore.","TWN":"雖然可以視作是神話中的大蛇，但是和家族聯盟流傳下來的傳統是不一樣的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치는 한때 인간을 지켜 주던 불사의 수호신이었습니다.","JPN":"オロチはかつて、人間を守っていた不死の守護神でした。","ENG":"Orochi once was an immortal guardian god that protected humans.","TWN":"大蛇曾經是守護人類的守護神。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};